  { match: ''Marque Repère Aromatisée Tequila'', fix: ''Marque Repère Tequila'' },
  { match: ''Dia Aromatisée à la Téquila'', fix: ''Dia Tequila'' },
];

let fixed = 0;
for \(const f of fixes\) {
  const { error } = await supabase.from\(''beers''\).update\({ name: f.fix }\).eq\(''name'', f.match\);
  if \(!error\) {
    console.log\(''  ✅ ""'' + f.match + ''"" → ""'' + f.fix + ''""''\);
