  }
}

// Also fix remaining ugly patterns: remove brewery duplication in name
let all = [];
let page = 0;
while \(true\) {
  const { data } = await supabase.from\(''beers''\).select\(''id, name, brewery''\).eq\(''is_active'', true\).range\(page * 1000, \(page + 1\) * 1000 - 1\);
  all = all.concat\(data\);
  if \(data.length < 1000\) break;
  page++;
}

// Fix names with duplicated brewery \(e.g., ''Heineken Heineken Premium''\)
let dupFixed = 0;
for \(const beer of all\) {
  const n = beer.name;
  const b = beer.brewery;
  // Check if brewery appears twice in name
  const bLower = b.toLowerCase\(\);
  const nLower = n.toLowerCase\(\);
  const firstIdx = nLower.indexOf\(bLower\);
  if \(firstIdx >= 0\) {
    const secondIdx = nLower.indexOf\(bLower, firstIdx + bLower.length\);
    if \(secondIdx >= 0\) {
      // Remove second occurrence
      const newName = n.substring\(0, secondIdx\) + n.substring\(secondIdx + b.length\).replace\(/^[\\s,]+/, ''''\);
