  all2 = all2.concat\(data\);
  if \(data.length < 1000\) break;
  page++;
}

const byKey = {};
for \(const b of all2\) {
  const key = \(b.brewery + ''||'' + b.name\).toLowerCase\(\).trim\(\);
  if \(!byKey[key]\) byKey[key] = [];
  byKey[key].push\(b\);
}

let dedup2 = 0;
for \(const [key, beers] of Object.entries\(byKey\)\) {
  if \(beers.length < 2\) continue;
  beers.sort\(\(a, b2\) => \(b2.total_votes || 0\) - \(a.total_votes || 0\)\);
  for \(let i = 1; i < beers.length; i++\) {
    await supabase.from\(''beers''\).update\({ is_active: false }\).eq\(''id'', beers[i].id\);
