const supabase = createClient\(''https://yuymwggxnaaoxlshwwyn.supabase.co'',''eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Inl1eW13Z2d4bmFhb3hsc2h3d3luIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzA5ODc5NjcsImV4cCI6MjA4NjU2Mzk2N30.sbJJGoNpp5tzvGGtXM4gnTtBGErixlPfMs15nSGnobM''\);

const fixes = [
  { match: ''75clchti Originale Blonde'', fix: ""Ch''ti Originale Blonde"" },
  { match: ''Extra Stout 4053400211428 Schankbier \(=7 bisig\) Stout'', fix: ''Guinness Extra Stout'' },
  { match: ""L''audacieuse cuvée speci''ale vendanges pinot Derain"", fix: ""L''Audacieuse Cuvée Vendanges"" },
  { match: ''Пиво светлое «Балтика экспортное» №7. Пастеризованное. Без консервантов'', fix: ''Baltika Export N°7'' },
];

for \(const f of fixes\) {
  const { error, count } = await supabase.from\(''beers''\).update\({ name: f.fix }\).eq\(''name'', f.match\).eq\(''is_active'', true\);
  console.log\(''✅ → ""'' + f.fix + ''""''\);
}

// Rebalance rarity
console.log\(''\\n🎲 Rebalancing rarity...''\);
let all = [];
let page = 0;
while \(true\) {
  const { data } = await supabase.from\(''beers''\).select\(''id, elo''\).eq\(''is_active'', true\).order\(''elo'', { ascending: true }\).range\(page * 1000, \(page + 1\) * 1000 - 1\);
  all = all.concat\(data\);
  if \(data.length < 1000\) break;
  page++;
}
// Sort by elo
all.sort\(\(a,b\) => a.elo - b.elo\);
const total = all.length;
const thresholds = {
  common: Math.floor\(total * 0.30\),
  rare: Math.floor\(total * 0.70\),
  epic: Math.floor\(total * 0.92\),
};

let updates = 0;
for \(let i = 0; i < all.length; i++\) {
  let rarity;
  if \(i < thresholds.common\) rarity = ''common'';
  else if \(i < thresholds.rare\) rarity = ''rare'';
  else if \(i < thresholds.epic\) rarity = ''epic'';
  else rarity = ''legendary'';

  const { error } = await supabase.from\(''beers''\).update\({ rarity }\).eq\(''id'', all[i].id\);
  if \(!error\) updates++;
}

const dist = { common: 0, rare: 0, epic: 0, legendary: 0 };
for \(let i = 0; i < all.length; i++\) {
  if \(i < thresholds.common\) dist.common++;
  else if \(i < thresholds.rare\) dist.rare++;
  else if \(i < thresholds.epic\) dist.epic++;
  else dist.legendary++;
