console.log\(''  Epic:      '' + dist.epic + '' \('' + \(dist.epic/total*100\).toFixed\(1\) + ''%\)''\);
console.log\(''  Legendary: '' + dist.legendary + '' \('' + \(dist.legendary/total*100\).toFixed\(1\) + ''%\)''\);
" --input-type=module)

